#!/usr/bin/env python3
"""fix_ts_errors2.py"""
import os, sys, subprocess, base64

ROOT = os.path.dirname(os.path.abspath(__file__))

def write(path, content):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print("  OK: " + path.replace(ROOT+"/",""))

print("=== fix_ts_errors2.py ===")
print("[1] git pull...")
r = subprocess.run(["git","pull","origin","main"], cwd=ROOT, capture_output=True, text=True)
print(" ", r.stdout.strip() or r.stderr.strip())

DRAFT_B64 = ""
ORDERS_B64 = ""
PDF_B64 = ""

write(ROOT+"/src/app/api/v1/estimates/draft/route.ts", base64.b64decode(DRAFT_B64).decode())
write(ROOT+"/src/app/api/v1/orders/[id]/route.ts", base64.b64decode(ORDERS_B64).decode())
write(ROOT+"/src/app/api/v1/orders/[id]/pdf/route.ts", base64.b64decode(PDF_B64).decode())

print("[2] tsc チェック...")
r = subprocess.run(["npx","tsc","--noEmit","--skipLibCheck"], cwd=ROOT, capture_output=True, text=True, timeout=120)
IGNORE = ["node_modules","@prisma/client",".prisma/client","next.config","scripts/","access-denied/"]
real_errors = [l for l in (r.stdout+r.stderr).splitlines() if "error TS" in l and not any(ig in l for ig in IGNORE)]
if real_errors:
    print("  tscエラー:")
    for l in real_errors[:20]: print("   ",l)
    sys.exit(1)
print("  OK 0件")

print("[3] git commit & push...")
files = ["src/app/api/v1/estimates/draft/route.ts","src/app/api/v1/orders/[id]/route.ts","src/app/api/v1/orders/[id]/pdf/route.ts"]
subprocess.run(["git","add"]+files, cwd=ROOT)
r = subprocess.run(["git","commit","-m","fix: tscエラー修正 withTenant括弧(draft/orders[id]/orders[id]pdf)"], cwd=ROOT, capture_output=True, text=True)
print(" ", r.stdout.strip())
r = subprocess.run(["git","push","origin","main"], cwd=ROOT, capture_output=True, text=True)
if r.returncode == 0:
    print("  PUSH OK")
else:
    print("  PUSH FAILED:", r.stderr.strip()); sys.exit(1)
os.remove(__file__)
print("OK!")
